def heuristic_crypto_extreme_silent_alert(today_stats: dict) -> tuple:
    """Flag when BTC RSI is extreme oversold (<20) but no crypto trades fired in 7d."""
    rsi_snapshot = today_stats.get("rsi_snapshot", {})
    btc = rsi_snapshot.get("BTC/USD", {})
    btc_rsi = btc.get("today", 50.0) if isinstance(btc, dict) else 50.0
    if btc_rsi >= 20:
        return False, ""
    by_strategy = today_stats.get("by_strategy", {})
    crypto_7d = (
        by_strategy.get("crypto-momentum", {}).get("trades_7d", 0)
        + by_strategy.get("crypto-oversold-bounce", {}).get("trades_7d", 0)
    )
    if crypto_7d == 0:
        return True, (
            f"PIPELINE_FAIL_RISK: BTC RSI={btc_rsi:.1f} (extreme oversold, <20) "
            f"+ 0 crypto trades 7d — crypto-monitor likely broken. "
            f"Manual check: gh workflow run crypto-monitor.yml"
        )
    return False, ""

