class TestCryptoExtremeSilentAlert(unittest.TestCase):
    def test_fires_on_extreme_oversold_and_silent(self):
        stats = {"rsi_snapshot": {"BTC/USD": {"today": 15.3}}, "by_strategy": {}}
        fired, reason = heuristic_crypto_extreme_silent_alert(stats)
        self.assertTrue(fired)
        self.assertIn("PIPELINE_FAIL_RISK", reason)
    def test_no_fire_when_btc_rsi_above_20(self):
        stats = {"rsi_snapshot": {"BTC/USD": {"today": 25.0}}, "by_strategy": {}}
        fired, _ = heuristic_crypto_extreme_silent_alert(stats)
        self.assertFalse(fired)
    def test_no_fire_when_crypto_trades_exist(self):
        stats = {"rsi_snapshot": {"BTC/USD": {"today": 14.0}}, "by_strategy": {"crypto-momentum": {"trades_7d": 1}}}
        fired, _ = heuristic_crypto_extreme_silent_alert(stats)
        self.assertFalse(fired)
    def test_missing_rsi_no_fire(self):
        fired, _ = heuristic_crypto_extreme_silent_alert({})
        self.assertFalse(fired)
